// Placeholder: replace with actual news API or RSS feed parsing
// Filter for mentions of Riverstone or PD Systems
const newsItems = [
  // Example structure:
  // { headline: 'Riverstone wins SHIELD contract', url: 'https://...', source: 'govcon_wire', published_at: '2026-01-15', partner: 'riverstone' },
];

const rsNews = newsItems.filter(n => n.partner === 'riverstone').map(n => ({ json: { partner_ou_tag: 'riverstone', items: [{ headline: n.headline, url: n.url, source: n.source, published_at: n.published_at }] } }));
const pdNews = newsItems.filter(n => n.partner === 'pd_systems').map(n => ({ json: { partner_ou_tag: 'pd_systems', items: [{ headline: n.headline, url: n.url, source: n.source, published_at: n.published_at }] } }));

return [...rsNews, ...pdNews];
